	//         "quoteCurrency": "USDT",
	//         "baseMinSize": "1.00000000",
	//         "quoteMinSize": "5.00000000",
	//         "baseMaxSize": "50000.00000000",
	//         "quoteMaxSize": "10000000000.00000000",
	//         "basePrec": "1",
	//         "quotePrec": "4"
	//     }
	//
	var marketId any = this.SafeString(market, "symbol")
